const b = $input.item.json.body || $input.item.json;
const nip = b.nip || $input.item.json.headers?.['x-nip'] || 'ADMIN';
const jumlah = parseInt(b.jumlah) || 0;
const masId = b.barangmasukid || null;
const kelId = b.barangkeluarid || null;
const delta = masId ? jumlah : -jumlah;
const barangid = masId || kelId;

return [{ json: {
  barangmasukid: masId,
  barangkeluarid: kelId,
  barangid: barangid,
  createdbyid: nip,
  jumlah: jumlah,
  delta: delta,
  keterangan: b.keterangan || '',
  tanggal: new Date().toISOString()
} }];
